final:
module full_adder (
    input a,
    input b,
    input cin,
    output sum,
    output cout
);

    wire s1, c1, c2;

    half_adder ha1 (.a(a), .b(b), .sum(s1), .cout(c1));
    half_adder ha2 (.a(s1), .b(cin), .sum(sum), .cout(c2));

  wire temp1_c1 = c1;
  wire temp2_c2 = c2;
  assign cout = temp1_c1 | temp2_c2;

endmodule

module half_adder (
    input a,
    input b,
    output sum,
    output cout
);

    assign sum = a ^ b;
    assign cout = a & b;

endmodule
